  ('pukao-6f0ba476-moex-00139', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '被繼承人之下列遺產，何者需列入遺產總額？①繼承人捐贈給臺北市政府之遺產  ②繼承人捐贈', '["繼承人捐贈部分遺產成立基金會", "遺產中之法定空地經被繼承人無償 供公眾通行之道路土地  ⑤遺產中作農業使用之農業用地", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00140', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '郭君112年度共支付受扶養80歲母親生活費30萬元，三子（24歲）之教育費30萬元。此外，郭君 贈與次子333萬元為創業基金，長子結婚贈與111萬元，請問郭君112年度之贈與總額為何？', '["374萬元", "344萬元", "130萬元", "100萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00141', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列有關土地增值稅稅率之敘述，何者正確？', '["土地增值稅稅率一律依土地漲價總數額累進課徵", "持有土地超過20年者，其土地增值稅即可減徵30%", "適用出售自用住宅用地優惠稅率一生僅一次", "土地增值稅稅額在新臺幣100元以下者免予課徵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00142', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列有關地價稅之敘述，何者正確？①地價稅之稅基為公告地價  ②地價稅之最高稅率為千分之', '["供公共使用之公有土地免徵地價稅", "地價稅納稅基準日為8月31日", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00143', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關公告地價，原則上應每幾年重新規定地價一次？有關房屋標準價格，應每幾年重新評定房屋 標準價格一次？', '["2年；2年", "2年；3年", "3年；3年", "3年；2年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00144', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依113年修正房屋稅條例規定，下列有關適用自住房屋稅率之規定，何者錯誤？', '["土地設定地上權之使用權房屋並供該使用權人自住使用者，其房屋稅率為1.2%", "房屋所有人、配偶或直系親屬應於該屋辦竣戶籍登記", "本人、配偶及直系親屬於全國僅持有一戶房屋，供自住且房屋現值在一定金額以下者，稅率為1%", "房屋無出租或供營業使用情形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00145', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '112年度每人基本生活費為20.2萬元，王先生一家五口包括本人及配偶及三名就學中之子女。倘 若王先生家之免稅額及一般扣除額合計為 70.8 萬元，特別扣除額包括薪資所得特別扣除額 20.7 萬元，財產交易損失10萬元、儲蓄投資特別扣除額10萬元、教育學費特別扣除額5萬元，請問 得自綜合所得總額中減除之基本生活費差額為多少？', '["0元", "5.2萬元", "15.2萬元", "30.2萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00146', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，下列何者非屬免稅所得？', '["教育、文化、公益、慈善機關或團體，符合行政院規定標準者，其本身之所得及其附屬作業組 織之所得", "個人取自營利事業贈與之財產", "公、教、軍、警人員及勞工所領政府發給之實物配給或其代金及房租津貼", "個人出售家庭日常使用之衣物、家具"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00147', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關出售房地，並適用房地合一稅之敘述，下列何者錯誤？', '["於完成所有權移轉登記日的次日起算30日內完成申報", "應以實際成交價額減除原始取得成本，與因取得、改良及移轉而支付的費用之餘額為所得額", "適用重購退稅之自用住宅，必須出售房地前6年，本人或其配偶、未成年子女設有戶籍並居住， 且無出租、供營業或執行業務使用", "適用重購退稅之自用住宅，於重購後5年內改作其他用途或再行移轉時，應追繳原扣抵或退還 稅額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00148', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依現行所得稅法，若綜合所得稅納稅義務人林先生選擇就其本人或配偶之各類所得分開計算稅 額，再由林先生合併報繳。假若納稅義務人林先生利息所得為14萬元，林先生的母親為受扶養親 屬的利息所得為 8 萬元，分開計稅之林太太的利息所得為 15 萬元，請問針對林太太可列報之儲 蓄投資特別扣除額的部分為多少？', '["5萬元", "13萬元", "15萬元", "23萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
